stepHooks.code:
try {
  const wd = sim.worldData
  if (!wd.__cf || !wd.__cf.hov || wd.__cf.hov.length !== 12) wd.__cf = { hov: Array(12).fill(0), prevDown: false, mx: 0, my: 0 }
  const C = wd.__cf
  const dt2 = Math.min(dt, 0.05)

  const hasMouse = wd.mouse_x !== undefined
  const tx = ((wd.mouse_x ?? 256) - 256) / 256
  const ty = ((wd.mouse_y ?? 256) - 256) / 256
  C.mx += (tx - C.mx) * Math.min(1, dt2 * 12)
  C.my += (ty - C.my) * Math.min(1, dt2 * 12)

  const GAMES = ["LIGHTHOUSE","GARNET","SELENE","HELIOS","NOCTURNE DISTRICT","TIDERUNNER","SIGNAL","PROOF","TV","ESPER","ORRERY","FABRIC"]
  const POSA = [[0.073,0.021],[-0.179,-0.008],[0.16,-0.15],[0.001,0.19],[-0.219,-0.196],[0.357,0.002],[-0.309,0.157],[0.071,-0.326],[0.242,0.259],[-0.458,-0.11],[0.442,-0.191],[-0.177,0.344]]
  const pos = i => POSA[i]

  let hovered = -1
  for (let i = 0; i < 12; i++) {
    const [px, py] = pos(i)
    const d = Math.hypot(tx - px, ty - py)
    const want = hasMouse && d < 0.10 ? 1 : 0
    if (want) hovered = i
    C.hov[i] += (want - C.hov[i]) * Math.min(1, dt2 * 8)
  }

  if (hovered !== (C.lastHover ?? -1) && typeof window !== 'undefined') {
    C.lastHover = hovered
    window.dispatchEvent(new CustomEvent('cafe:hover', { detail: hovered >= 0 ? GAMES[hovered] : null }))
  }

  // tell the shell where the doors are (uv space) — it pins live head-counts
  if (!C.sentPortals && typeof window !== 'undefined') {
    C.sentPortals = 1
    window.dispatchEvent(new CustomEvent('cafe:portals', {
      detail: GAMES.map((g, i) => ({ name: g, x: POSA[i][0], y: POSA[i][1], r: 0.10 })),
    }))
  }

  const down = !!wd.mouse_down
  if (down && !C.prevDown && hovered >= 0 && typeof window !== 'undefined') {
    window.dispatchEvent(new CustomEvent('cafe:launch', { detail: GAMES[hovered] }))
  }
  C.prevDown = down

  wd.gpuUniforms = [C.mx, C.my, ...C.hov]
} catch (e) { /* keep the door open */ }

