// ── the channel words: each is a callable shader — signature (q: -1..1 screen, t) ──

fn ch_static(q: vec2f, t: f32) -> vec3f {
  let n = hash21(floor(q * vec2f(160.0, 120.0)) + floor(t * 60.0) * 7.3);
  var v = 0.25 + 0.75 * n;
  // rolling tear bar
  let bar = fract(q.y * 0.5 - t * 0.35);
  if (bar < 0.06) { v *= 0.45; }
  return vec3f(v);
}

fn ch_plasma(q: vec2f, t: f32) -> vec3f {
  var v = sin(q.x * 6.0 + t * 1.2);
  v += sin((q.y * 5.0 + t) * 0.8);
  v += sin((q.x + q.y) * 4.0 + t * 0.7);
  v += sin(length(q * 5.0) - t * 1.5);
  v *= 0.25;
  return vec3f(0.5 + 0.5 * sin(6.2831 * v), 0.5 + 0.5 * sin(6.2831 * v + 2.1), 0.5 + 0.5 * sin(6.2831 * v + 4.2));
}

fn ch_pong(q: vec2f, t: f32) -> vec3f {
  var col = vec3f(0.02, 0.03, 0.02);
  // net
  if (abs(q.x) < 0.012 && fract(q.y * 5.0) < 0.55) { col = vec3f(0.35); }
  // paddles (hook-simulated)
  if (abs(q.x + 0.85) < 0.03 && abs(q.y - uni(5)) < 0.16) { col = vec3f(1.4); }
  if (abs(q.x - 0.85) < 0.03 && abs(q.y - uni(6)) < 0.16) { col = vec3f(1.4); }
  // ball
  if (abs(q.x - uni(3)) < 0.035 && abs(q.y - uni(4)) < 0.045) { col = vec3f(1.8); }
  // score pips
  for (var i = 0; i < 5; i++) {
    if (f32(i) < uni(7) && length(q - vec2f(-0.5 + f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
    if (f32(i) < uni(8) && length(q - vec2f(0.5 - f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
  }
  return col;
}

fn ch_boids(q: vec2f, t: f32) -> vec3f {
  var col = mix(vec3f(0.03, 0.05, 0.10), vec3f(0.10, 0.14, 0.22), q.y * -0.5 + 0.5);
  // moon
  col += vec3f(0.5, 0.5, 0.42) * exp(-length(q - vec2f(0.55, -0.55)) * 9.0);
  // the flock (hook-simulated)
  for (var i = 0; i < 16; i++) {
    let b = vec2f(uni(10 + i * 2), uni(11 + i * 2));
    let d = length(q - b);
    if (d < 0.028) { col = vec3f(0.02); }                    // bird body
    col += vec3f(0.05, 0.05, 0.04) * exp(-d * 40.0);         // faint presence
  }
  return col;
}


fn sc_box(p: vec2f, c: vec2f, b: vec2f, r: f32) -> f32 {
  let d = abs(p - c) - b;
  return length(max(d, vec2f(0.0))) + min(max(d.x, d.y), 0.0) - r;
}

// CH 5 — SITCOM. The hook runs four little lives through behavior zones
// (couch, kitchen, window, door, center-stage); the tube just draws them.
fn ch_sitcom(q: vec2f, t: f32) -> vec3f {
  let FLOOR = 0.42;
  // the set: warm wall, wood floor
  var col = mix(vec3f(0.20, 0.14, 0.11), vec3f(0.13, 0.09, 0.08), q.y * 0.5 + 0.5);
  col *= 0.94 + 0.06 * sin(q.x * 40.0);
  if (q.y > FLOOR) {
    col = mix(vec3f(0.17, 0.11, 0.06), vec3f(0.10, 0.06, 0.04), (q.y - FLOOR) * 1.6);
    col *= 0.9 + 0.1 * sin(q.x * 24.0 + q.y * 60.0);
  }
  // window on the night
  let wd2 = sc_box(q, vec2f(-0.72, -0.28), vec2f(0.13, 0.17), 0.02);
  if (wd2 < 0.0) {
    col = vec3f(0.02, 0.03, 0.07);
    if (hash21(floor(q * 30.0)) > 0.992) { col += vec3f(0.6); }
    col += vec3f(0.35, 0.35, 0.30) * exp(-length(q - vec2f(-0.68, -0.38)) * 14.0);
    if (abs(q.x + 0.72) < 0.012 || abs(q.y + 0.28) < 0.012) { col = vec3f(0.24, 0.17, 0.12); }
  } else if (wd2 < 0.02) { col = vec3f(0.26, 0.19, 0.13); }
  // the door — uni(2) swings it open on a dark hallway
  let dOpen = uni(2);
  let dframe = sc_box(q, vec2f(0.86, 0.12), vec2f(0.11, 0.30), 0.01);
  if (dframe < 0.0) {
    col = vec3f(0.03, 0.025, 0.032);
    if (q.x > 0.75 + dOpen * 0.17) {
      col = vec3f(0.23, 0.15, 0.09) * (0.85 + 0.15 * sin(q.y * 30.0));
      if (length(q - vec2f(0.78 + dOpen * 0.17, 0.14)) < 0.012) { col = vec3f(0.55, 0.45, 0.25); }
    }
  } else if (dframe < 0.018) { col = vec3f(0.28, 0.20, 0.13); }
  // couch
  let cc = vec2f(-0.30, 0.32);
  if (sc_box(q, cc + vec2f(0.0, -0.10), vec2f(0.27, 0.09), 0.04) < 0.0) { col = vec3f(0.36, 0.11, 0.11); }
  if (sc_box(q, cc + vec2f(0.0, 0.05), vec2f(0.27, 0.06), 0.04) < 0.0) {
    col = vec3f(0.45, 0.14, 0.13);
    if (abs(q.x - cc.x) < 0.004) { col *= 0.8; }
  }
  if (sc_box(q, cc + vec2f(-0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0 ||
      sc_box(q, cc + vec2f(0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0) { col = vec3f(0.42, 0.13, 0.12); }
  // kitchen counter + mug
  if (sc_box(q, vec2f(0.52, 0.47), vec2f(0.14, 0.08), 0.01) < 0.0) { col = vec3f(0.20, 0.16, 0.12); }
  if (sc_box(q, vec2f(0.52, 0.385), vec2f(0.155, 0.014), 0.005) < 0.0) { col = vec3f(0.55, 0.50, 0.42); }
  if ((i32(uni(9) + 0.5) & 2) == 0 && sc_box(q, vec2f(0.47, 0.355), vec2f(0.012, 0.014), 0.004) < 0.0) { col = vec3f(0.75, 0.68, 0.60); }
  // lamp — a real object: someone can turn it off (uni 9 bit 0)
  let props = i32(uni(9) + 0.5);
  let lampOn = f32(props & 1);
  if (abs(q.x - 0.13) < 0.006 && q.y > -0.02 && q.y < FLOOR) { col = vec3f(0.1, 0.1, 0.1); }
  if (q.y > -0.11 && q.y < -0.02 && abs(q.x - 0.13) < 0.035 + (q.y + 0.11) * 0.45) {
    col = mix(vec3f(0.16, 0.14, 0.13), vec3f(0.85, 0.65, 0.35), lampOn);
  }
  col += vec3f(0.5, 0.35, 0.15) * exp(-length((q - vec2f(0.13, 0.05)) * vec2f(1.0, 0.8)) * 3.2) * 0.35 * lampOn;

  // ── the cast (uni 42..61: x, pose, face, talk, row per character) ──
  for (var i = 0; i < 4; i++) {
    let ux = uni(42 + i * 5);
    let pose = uni(43 + i * 5);
    if (pose > 2.5) { continue; }
    let face = uni(44 + i * 5);
    let talk = uni(45 + i * 5);
    let row = uni(46 + i * 5);
    let fi = f32(i);
    var shirt = vec3f(0.75, 0.55, 0.15);
    var hair = vec3f(0.12, 0.09, 0.05);
    if (i == 1) { shirt = vec3f(0.15, 0.50, 0.50); hair = vec3f(0.35, 0.20, 0.08); }
    if (i == 2) { shirt = vec3f(0.55, 0.22, 0.10); hair = vec3f(0.08, 0.08, 0.08); }
    if (i == 3) { shirt = vec3f(0.35, 0.18, 0.42); hair = vec3f(0.50, 0.45, 0.40); }
    let hgt = 0.30 + fi * 0.014;
    let sitting = pose > 1.5;
    let walking = abs(pose - 1.0) < 0.25;
    let bob = select(0.0, abs(sin(t * 7.0 + fi * 2.0)) * 0.012, walking);
    let feetY = select(FLOOR + row, 0.415, sitting) - bob;
    let hipY = select(feetY - hgt * 0.42, 0.285, sitting);   // cushion top, not inside it
    let torsoC = vec2f(ux, hipY - hgt * 0.19);
    let headC = vec2f(ux + face * 0.008, hipY - hgt * 0.36);
    if (sitting) {
      // thigh out along the seat, shin down to the floor
      let kneeX = ux + face * 0.055;
      if (sc_box(q, vec2f((ux + kneeX) * 0.5, hipY + 0.012), vec2f(abs(kneeX - ux) * 0.5 + 0.008, 0.014), 0.008) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
      if (sc_box(q, vec2f(kneeX, (hipY + 0.012 + feetY) * 0.5), vec2f(0.011, (feetY - hipY - 0.012) * 0.5), 0.006) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    } else {
      let sw = select(0.0, sin(t * 9.0 + fi * 2.0) * 0.016, walking);
      if (sc_box(q, vec2f(ux - 0.014 + sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0 ||
          sc_box(q, vec2f(ux + 0.014 - sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    }
    if (sc_box(q, torsoC, vec2f(0.036, hgt * 0.20), 0.02) < 0.0) { col = shirt; }
    let hd = length(q - headC);
    if (hd < 0.036) { col = vec3f(0.85, 0.62, 0.45); }
    if (hd < 0.038 && q.y < headC.y - 0.010) { col = hair; }
    if (fract(t * 0.31 + fi * 0.37) > 0.06) {
      if (length(q - (headC + vec2f(face * 0.012 - 0.008, 0.004))) < 0.0035 ||
          length(q - (headC + vec2f(face * 0.012 + 0.008, 0.004))) < 0.0035) { col = vec3f(0.05, 0.05, 0.05); }
    }
    if (talk > 0.5 && talk < 1.5) {
      let bc = headC + vec2f(face * 0.11, -0.105);
      let bd = sc_box(q, bc, vec2f(0.065, 0.030), 0.02);
      if (bd < 0.0) {
        col = vec3f(0.92, 0.92, 0.90);
        for (var k = 0; k < 3; k++) {
          if (fract(t * 0.9 + fi * 0.5) > f32(k) * 0.3 &&
              length(q - (bc + vec2f(-0.03 + f32(k) * 0.03, 0.0))) < 0.008) { col = vec3f(0.25, 0.25, 0.25); }
        }
      } else if (bd < 0.006 && bd >= 0.0) { col = vec3f(0.6, 0.6, 0.58); }
    } else if (talk > 1.5 && talk < 2.5) {
      // "!" — something just happened
      let bc = headC + vec2f(face * 0.05, -0.095);
      let bd = sc_box(q, bc, vec2f(0.026, 0.028), 0.016);
      if (bd < 0.0) {
        col = vec3f(0.95, 0.90, 0.70);
        if (abs(q.x - bc.x) < 0.005 && q.y > bc.y - 0.018 && q.y < bc.y + 0.006) { col = vec3f(0.55, 0.15, 0.10); }
        if (length(q - (bc + vec2f(0.0, 0.016))) < 0.005) { col = vec3f(0.55, 0.15, 0.10); }
      } else if (bd < 0.005 && bd >= 0.0) { col = vec3f(0.65, 0.55, 0.40); }
    } else if (talk > 2.5) {
      // the mug, in hand — raised for a sip now and then, steam curling
      let sip = smoothstep(0.55, 0.9, sin(t * 1.1 + fi * 2.0)) * 0.035;
      let mc = vec2f(ux + face * 0.052, hipY - hgt * 0.16 - sip);
      if (sc_box(q, mc, vec2f(0.013, 0.015), 0.004) < 0.0) { col = vec3f(0.75, 0.68, 0.60); }
      let sx = mc.x + sin((mc.y - q.y) * 30.0 + t * 2.0) * 0.008;
      if (q.y < mc.y - 0.02 && q.y > mc.y - 0.07 && abs(q.x - sx) < 0.004) {
        col = mix(col, vec3f(0.7, 0.7, 0.72), 0.35 * (1.0 - (mc.y - q.y) * 14.0));
      }
    }
  }
  // lights out: the room falls into blue moonlight until someone fixes it
  col *= mix(vec3f(0.34, 0.38, 0.55), vec3f(1.0, 1.0, 1.0), lampOn);
  // the laugh: warm audience light washing up from below
  col += vec3f(0.45, 0.32, 0.12) * uni(62) * (0.6 + 0.4 * sin(t * 18.0)) * (0.3 + 0.7 * smoothstep(0.0, 0.8, q.y));
  return col;
}

fn visual_tv_set(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
  let t = time;

  // the room: dark, lit by the set
  var col = vec3f(0.012, 0.011, 0.015) * (1.0 + 0.35 * fbm3(p * 0.01));

  let C = vec2f(256.0, 238.0);
  let half = vec2f(172.0, 122.0);
  let dBez = sdRoundedBox(p - C, half + vec2f(22.0, 26.0), 14.0);
  let dScr = sdRoundedBox(p - C, half, 10.0);

  // glow spill on the room
  let flick = 0.94 + 0.06 * sin(t * 47.0) * sin(t * 31.0);
  col += vec3f(0.10, 0.12, 0.16) * flick * exp(-max(dBez, 0.0) * 0.02);

  // bezel: warm plastic with a highlight
  if (dBez < 0.0 && dScr >= 0.0) {
    col = mix(vec3f(0.10, 0.085, 0.07), vec3f(0.16, 0.14, 0.12), fbm3(p * 0.15) * 0.5);
    col *= 0.8 + 0.4 * smoothstep(20.0, -30.0, p.y - (C.y - half.y));
    // channel knob
    let kd = length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)));
    if (kd < 7.0) {
      col = vec3f(0.05);
      let ka = 6.2831 * uni(0) / 5.0 - 1.57;
      if (length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)) - vec2f(cos(ka), sin(ka)) * 4.0) < 1.6) { col = vec3f(0.7); }
    }
  }

  // the screen: barrel-distorted, phosphor, scanlines — a CRT calling a channel
  if (dScr < 0.0) {
    var q = (p - C) / half;                                   // -1..1
    q *= 1.0 + 0.10 * dot(q, q);                              // barrel
    if (abs(q.x) > 1.0 || abs(q.y) > 1.0) {
      col = vec3f(0.0);                                       // over-scan black
    } else {
      // ── THE CALL: channel word by number ──
      let ch = i32(uni(0) + 0.5);
      var scr: vec3f;
      if (ch == 0) { scr = ch_static(q, t); }
      else if (ch == 1) { scr = ch_plasma(q, t); }
      else if (ch == 2) { scr = ch_pong(q, t); }
      else if (ch == 3) { scr = ch_boids(q, t); }
      else { scr = ch_sitcom(q, t); }

      // switch burst: static bleeds over the program
      if (uni(1) > 0.01) { scr = mix(scr, ch_static(q, t * 3.0), min(uni(1) * 1.4, 1.0)); }

      // a watcher's attention warms the scene — hearth-light where the
      // cursor rests (and where a fellow watcher's orb rests). Nothing moves.
      for (var wi = 0; wi < 2; wi++) {
        var m = params.xy;
        if (wi == 1) { m = params.zw; }
        if (m.x > -2000.0) {
          let mq = (m - C) / half;
          let warm = exp(-length(q - mq) * 2.4);
          scr *= 1.0 + 0.20 * warm;
          scr = mix(scr, scr * vec3f(1.10, 1.00, 0.85), min(warm, 1.0) * 0.8);
        }
      }

      // CRT dress: phosphor triads, scanlines, corner falloff, flicker
      let px = i32(p.x * 3.0) % 3;
      var mask = vec3f(0.85);
      if (px == 0) { mask = vec3f(1.25, 0.72, 0.72); }
      else if (px == 1) { mask = vec3f(0.72, 1.25, 0.72); }
      else { mask = vec3f(0.72, 0.72, 1.25); }
      scr *= mask;
      scr *= 0.82 + 0.18 * sin(p.y * 3.14159);                // scanlines
      scr *= flick;
      scr *= 1.0 - 0.45 * pow(length(q), 4.0);                // corner falloff
      col = scr * 1.35;                                       // HDR — bloom catches the tube
    }
  }

  // set shadow on the floor
  col *= 1.0 - 0.3 * smoothstep(30.0, 0.0, abs(p.y - (C.y + half.y + 40.0))) * smoothstep(half.x + 40.0, half.x - 20.0, abs(p.x - C.x));

  return vec4f(col, 1.0);
}

fn cf_portal_pos(i: i32) -> vec2f {
  if (i == 0) { return vec2f(0.073, 0.021); }
  if (i == 1) { return vec2f(-0.179, -0.008); }
  if (i == 2) { return vec2f(0.16, -0.15); }
  if (i == 3) { return vec2f(0.001, 0.19); }
  if (i == 4) { return vec2f(-0.219, -0.196); }
  if (i == 5) { return vec2f(0.357, 0.002); }
  if (i == 6) { return vec2f(-0.309, 0.157); }
  if (i == 7) { return vec2f(0.071, -0.326); }
  if (i == 8) { return vec2f(0.242, 0.259); }
  if (i == 9) { return vec2f(-0.458, -0.11); }
  if (i == 10) { return vec2f(0.442, -0.191); }
  if (i == 11) { return vec2f(-0.177, 0.344); }
  return vec2f(0.0, 0.0);
}
fn cf_style(i: i32) -> i32 {
  if (i == 0) { return 8; }
  if (i == 1) { return 2; }
  if (i == 2) { return 8; }
  if (i == 3) { return 8; }
  if (i == 4) { return 8; }
  if (i == 5) { return 6; }
  if (i == 6) { return 7; }
  if (i == 7) { return 8; }
  if (i == 8) { return 8; }
  if (i == 9) { return 8; }
  if (i == 10) { return 1; }
  if (i == 11) { return 0; }
  return 8;
}
fn cf_hue(i: i32) -> f32 {
  if (i == 0) { return 0.420; }
  if (i == 1) { return 0.980; }
  if (i == 2) { return 0.660; }
  if (i == 3) { return 0.990; }
  if (i == 4) { return 0.160; }
  if (i == 5) { return 0.130; }
  if (i == 6) { return 0.400; }
  if (i == 7) { return 0.760; }
  if (i == 8) { return 0.960; }
  if (i == 9) { return 0.250; }
  if (i == 10) { return 0.050; }
  if (i == 11) { return 0.720; }
  return 0.5;
}

fn cf_stars(p: vec2f, t: f32) -> vec3f {
  var c = vec3f(0.008, 0.007, 0.016);
  c += vec3f(0.05, 0.025, 0.09) * smoothstep(0.4, 0.9, fbm(p * 1.5 + vec2f(t * 0.004, 0.0), 4));
  for (var l = 0; l < 2; l++) {
    let fl = f32(l);
    let sp = p * (16.0 + fl * 26.0) + fl * 31.0;
    let cell = floor(sp);
    let h = hash21(cell);
    let fp = fract(sp) - 0.5;
    let tw = 0.5 + 0.5 * sin(t * (0.5 + h * 1.4) + h * 40.0);
    c += vec3f(0.8, 0.75, 0.95) * step(0.985, h) * smoothstep(0.24, 0.03, length(fp)) * tw * (1.1 - fl * 0.4);
  }
  return c;
}

fn visual_cf_world(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mp = vec2f(uni(0), uni(1));     // cursor in field coords

  // ── the room: stars seen through curved space (your cursor is a lens) ──
  var p = uv;
  let md = uv - mp;
  let mr2 = max(dot(md, md), 0.002);
  p -= md * (0.010 / mr2) * smoothstep(0.9, 0.2, length(md));
  var col = cf_stars(p, t);

  // warm hearth-light from below — this is a cafe, not a void
  col += vec3f(0.10, 0.055, 0.02) * pow(max(0.0, uv.y + 0.2), 2.0) * (0.8 + 0.2 * sin(t * 0.7));

  // ── every cartridge on the shelf, newest nearest the center ──
  for (var i = 0; i < 12; i++) {
    let ctr = cf_portal_pos(i);
    let d = length(uv - ctr);
    let R = 0.088;
    let hov = uni(2 + i);                          // 0..1 hover bloom from the hook
    let rr = R * (1.0 + hov * 0.12);
    if (d < rr) {
      let q = (uv - ctr) / rr;                     // -1..1 inside the disc
      var g = vec3f(0.0);
      let st = cf_style(i);
      if (st == 0) {
        // FABRIC — a lens wandering through stars
        var pp = q * 2.0;
        let lc = vec2f(sin(t * 0.6) * 0.5, cos(t * 0.47) * 0.4);
        let ld = pp - lc;
        pp -= ld * (0.16 / max(dot(ld, ld), 0.02));
        g = cf_stars(pp * 1.6, t) * 2.2;
        g += vec3f(0.5, 0.9, 1.1) * exp(-dot(ld, ld) * 14.0) * 0.4;
      } else if (st == 1) {
        // ORRERY — three worlds around a coal
        g = vec3f(0.02, 0.015, 0.03);
        g += vec3f(3.0, 1.7, 0.5) * exp(-dot(q, q) * 30.0);
        for (var k = 1; k <= 3; k++) {
          let fk = f32(k);
          let a = t * (0.9 - fk * 0.18) + fk * 2.1;
          let pp = q - vec2f(cos(a), sin(a)) * (0.22 + fk * 0.17);
          var pc = vec3f(0.45, 0.5, 0.65);
          if (k == 2) { pc = vec3f(0.2, 0.45, 0.8); }
          if (k == 3) { pc = vec3f(0.8, 0.5, 0.25); }
          g += pc * exp(-dot(pp, pp) * 260.0) * 1.6;
        }
      } else if (st == 2) {
        // GARNET — the crystal
        let qa = rotate(q, t * 0.4);
        let cd = abs(qa.x) * 0.866 + abs(qa.y) * 0.5;
        let inside = smoothstep(0.62, 0.58, max(cd, abs(qa.y)));
        let facet = 0.6 + 0.4 * sin(qa.x * 9.0 + qa.y * 7.0 + t * 0.8);
        g = mix(vec3f(0.02, 0.01, 0.02), vec3f(0.75, 0.18, 0.25) * facet, inside);
        g += vec3f(1.6, 0.9, 0.7) * pow(max(0.0, facet - 0.75) * 4.0, 2.0) * inside;
      } else if (st == 3) {
        // ONE DAY — a sky that keeps its whole day
        let ph = fract(t * 0.05);
        let el = sin(ph * 6.28318) * 0.8;
        let day = smoothstep(-0.2, 0.4, el);
        g = mix(vec3f(0.02, 0.02, 0.06), vec3f(0.25, 0.5, 0.8), day * (0.5 - q.y * 0.5));
        g = mix(g, vec3f(0.9, 0.4, 0.15), smoothstep(0.3, 0.0, abs(el)) * max(0.0, -q.y + 0.2) * 0.9);
        let sun = vec2f(cos(ph * 6.28318 - 1.57) * 0.6, -el * 0.55 + 0.1);
        g += vec3f(3.0, 2.0, 0.9) * exp(-dot(q - sun, q - sun) * 60.0) * max(day, 0.15);
        if (q.y > 0.25) { g = mix(g, g * vec3f(0.5, 0.6, 0.8), 0.6); }   // the sea below
      } else if (st == 4) {
        // SAIL — one boat, one sea
        g = mix(vec3f(0.35, 0.5, 0.65), vec3f(0.05, 0.14, 0.2), smoothstep(-0.1, 0.5, q.y));
        let w = sin(q.x * 9.0 + t * 1.4) * 0.05;
        g = mix(g, vec3f(0.03, 0.10, 0.14), smoothstep(w + 0.02, w - 0.02, -q.y + 0.1) * 0.0 + smoothstep(w - 0.02, w + 0.06, q.y - 0.05));
        let sail = max(max(-(q.x + 0.05) * 3.0, q.y + 0.15), (q.x * 0.9 + q.y * 0.8) - 0.28);
        g = mix(g, vec3f(1.0, 0.96, 0.88), smoothstep(0.02, -0.02, sail));
      } else if (st == 5) {
        // SOLSTICE — a sun you carry over a valley
        g = vec3f(0.03, 0.04, 0.09);
        let sp = vec2f(sin(t * 0.5) * 0.45, -0.3 + cos(t * 0.5) * 0.12);
        g += vec3f(3.2, 2.2, 0.9) * exp(-dot(q - sp, q - sp) * 40.0);
        let hill = q.y - (0.25 + 0.15 * sin(q.x * 3.0 + 1.0));
        let lit = max(0.0, 1.0 - length(q - sp) * 1.4);
        g = mix(g, mix(vec3f(0.03, 0.05, 0.02), vec3f(0.15, 0.3, 0.08), lit), smoothstep(-0.02, 0.02, hill));
      } else if (st == 6) {
        // TIDERUNNER — wind over water
        let band = sin(q.y * 14.0 - t * 1.1 + sin(q.x * 4.0) * 0.7);
        g = mix(vec3f(0.05, 0.13, 0.17), vec3f(0.12, 0.25, 0.3), 0.5 + 0.5 * band);
        g += vec3f(0.8, 0.85, 0.85) * pow(max(0.0, band - 0.8) * 5.0, 2.0) * 0.4;
        let bt = q - vec2f(sin(t * 0.4) * 0.4, 0.0);
        g += vec3f(0.9, 0.85, 0.75) * exp(-dot(bt, bt) * 300.0) * 1.2;
      } else if (st == 7) {
        // SIGNAL — a television waiting for a word
        let sn = hash21(floor(q * 24.0) + floor(t * 9.0));
        g = vec3f(sn * 0.5);
        g += vec3f(0.3, 1.0, 0.45) * exp(-dot(q, q) * 8.0) * (0.28 + 0.14 * sin(t * 2.0));
        g *= 0.82 + 0.18 * sin(q.y * 60.0 - t * 8.0);
      } else {
        // a young world — a banded seed-planet in its own hue
        let hue = cf_hue(i);
        let cA = 0.5 + 0.5 * cos(6.2831 * (hue + vec3f(0.0, 0.33, 0.67)));
        g = cA * (0.22 + 0.5 * fbm3(q * 3.0 + vec2f(t * 0.08, f32(i) * 3.7)));
        g += cA * 0.4 * smoothstep(0.6, 1.0, 1.0 - abs(q.y * 2.2 + 0.3 * sin(q.x * 3.0 + t * 0.4)));
        let mn = q - vec2f(cos(t * 0.5 + f32(i) * 1.9), sin(t * 0.5 + f32(i) * 1.9) * 0.6) * 0.78;
        g += vec3f(0.85) * exp(-dot(mn, mn) * 260.0);
        g *= 0.85 + 0.3 * (1.0 - length(q));
      }
      // glass edge + hover bloom
      let edge = smoothstep(1.0, 0.86, length(q));
      col = mix(col, g, edge);
      col += vec3f(1.2, 0.85, 0.4) * exp(-pow((length(q) - 0.97) * 9.0, 2.0)) * (0.25 + hov * 1.3);
    } else {
      // halo when hovered
      col += vec3f(1.0, 0.7, 0.3) * exp(-pow((d - rr) * 22.0, 2.0)) * hov * 0.8;
    }
  }

  // the cursor itself — a soft ember
  col += vec3f(1.4, 0.9, 0.4) * exp(-dot(uv - mp, uv - mp) * 900.0) * 0.8;

  if (col.x != col.x || col.y != col.y || col.z != col.z) { col = vec3f(0.01); }
  return vec4f(clamp(col, vec3f(0.0), vec3f(60.0)), 1.0);
}
